const res = $input.first().json;
const rows = res.values || [];
const pending = [];
for (let i = 0; i < rows.length; i++) {
  if ((rows[i][1]||'').toString().trim() === 'Approved') pending.push({ idx: i, row: rows[i] });
}
if (!pending.length) throw new Error('No Approved rows. Set column B = Approved in Fitness Topics sheet.');
const found = pending[Math.floor(Math.random() * pending.length)];
const sheetRow = found.idx + 2;
return [{ json: {
  job_id:         (found.row[0]||'').trim() || ('FIT-' + Date.now().toString().slice(-8)),
  status:         (found.row[1]||'Approved').trim(),
  exercise_name:  (found.row[2]||'').trim(),
  target_muscles: (found.row[3]||'').trim(),
  exercise_type:  (found.row[4]||'Strength').trim(),
  difficulty:     (found.row[5]||'Beginner').trim(),
  equipment:      (found.row[6]||'Bodyweight').trim(),
  reps_sets:      (found.row[7]||'3 sets x 12 reps').trim(),
  key_tip:        (found.row[8]||'').trim(),
  cta_message:    (found.row[9]||'Follow for daily workouts').trim(),
  popup_header:   (found.row[10]||'FitChannel').trim(),
  popup_message:  (found.row[11]||'Get the full program!').trim(),
  hashtags:       (found.row[12]||'#fitness #workout').trim(),
  category:       (found.row[13]||'Strength').trim(),
  sheet_row:      sheetRow,
  source:         'google_sheet'
}}];

const raw  = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;

let d = {};
try { d = $('Pick Approved Topic').first().json; } catch(e) {}

const jobId        = body.job_id        || d.job_id        || ('FIT-' + Date.now().toString().slice(-8));
const exerciseName = body.exercise_name || d.exercise_name || body.topic || '';

if (!exerciseName) throw new Error('No exercise_name. Add topics to Fitness Topics sheet (col C) or send via webhook.');

return [{ json: {
  job_id:         jobId,
  exercise_name:  exerciseName,
  target_muscles: body.target_muscles || d.target_muscles || 'Full Body',
  exercise_type:  body.exercise_type  || d.exercise_type  || 'Strength',
  difficulty:     body.difficulty     || d.difficulty     || 'Beginner',
  equipment:      body.equipment      || d.equipment      || 'Bodyweight',
  reps_sets:      body.reps_sets      || d.reps_sets      || '3 sets x 12 reps',
  key_tip:        body.key_tip        || d.key_tip        || 'Control every rep',
  cta_message:    body.cta_message    || d.cta_message    || 'Follow for daily workouts',
  popup_header:   body.popup_header   || d.popup_header   || 'FitChannel',
  popup_message:  body.popup_message  || d.popup_message  || 'Get the full program!',
  hashtags:       body.hashtags       || d.hashtags       || '#fitness #workout #gym',
  category:       body.category       || d.category       || 'Strength',
  sheet_row:      body.sheet_row      || d.sheet_row      || null,
  num_clips:      6,
  clip_dur_sec:   5,
  word_target:    75,
  start_time:     Date.now()
}}];

const response = $input.first().json;
const config   = $('Set Job Config').first().json;

// Claude API response format: response.content[0].text
if (!response.content || !response.content[0] || !response.content[0].text)
  throw new Error('Claude response empty — check ANTHROPIC_API_KEY env var. Error: ' + JSON.stringify(response).slice(0,200));

let raw = response.content[0].text.trim();
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

let parsed;
try { parsed = JSON.parse(raw); }
catch(e) {
  const s = raw.indexOf('{'), end = raw.lastIndexOf('}');
  if (s === -1 || end === -1) throw new Error('Gemini did not return valid JSON: ' + raw.slice(0, 300));
  parsed = JSON.parse(raw.slice(s, end + 1));
}

if (!parsed.scenes || !Array.isArray(parsed.scenes))
  throw new Error('Gemini response missing scenes array');

const TARGET = 6;
while (parsed.scenes.length < TARGET) {
  const i = parsed.scenes.length;
  const last = parsed.scenes[parsed.scenes.length - 1];
  parsed.scenes.push({ ...last, scene_number: i+1, start_sec: i*5, end_sec: (i+1)*5 });
}
parsed.scenes = parsed.scenes.slice(0, TARGET);

const seedance_prompts = parsed.scenes.map(s => s.visual_prompt || '');
const negative_prompts = parsed.scenes.map(s => s.negative_prompt || 'text, labels, watermarks, cartoon, anime, blurry, dark background');
const popup = parsed.popup || { start_sec: 5, end_sec: 9, app_name: config.popup_header, message: config.popup_message };
const muscleLabels = parsed.muscle_labels_scene4 || [];

console.log('Script parsed: ' + parsed.scenes.length + ' scenes | title: ' + parsed.title + ' | muscle_labels: ' + muscleLabels.length);

return [{ json: {
  ...config,
  narration:             parsed.narration,
  scenes:                parsed.scenes,
  seedance_prompts,
  negative_prompts,
  title:                 parsed.title    || config.exercise_name,
  hashtags:              parsed.hashtags || config.hashtags,
  highlight_keywords:    parsed.highlight_keywords || ['PUSH', 'SQUEEZE', 'BREATHE'],
  muscle_labels_scene4:  muscleLabels,
  popup
}}];

const fs           = require('fs');
const https        = require('https');
const { execSync } = require('child_process');

const jobData   = $input.first().json;
const jobId     = jobData.job_id;
const narration = (jobData.narration || '').substring(0, 3000);
const n8nIn     = '/data/ffmpeg/input';
if (!fs.existsSync(n8nIn)) fs.mkdirSync(n8nIn, { recursive: true });

const ELEVEN_API_KEY  = 'sk_2022a552bc24219053bf31a93d51c447ebc13439f561e104';
const ELEVEN_VOICE_ID = 'TVm8lq6qGcfDUgEiSSn5';
const ELEVEN_MODEL    = 'eleven_turbo_v2_5';

const audioPath = n8nIn + '/' + jobId + '_voice.mp3';
const contAudio = '/ffmpeg/input/' + jobId + '_voice.mp3';

// ── Call /with-timestamps endpoint — returns audio + real character timestamps ──
const payload = JSON.stringify({
  text: narration,
  model_id: ELEVEN_MODEL,
  voice_settings: { stability: 0.45, similarity_boost: 0.80, style: 0.15, use_speaker_boost: true }
});

const response = await new Promise((resolve, reject) => {
  const chunks = [];
  const req = https.request({
    hostname: 'api.elevenlabs.io',
    path: '/v1/text-to-speech/' + ELEVEN_VOICE_ID + '/with-timestamps',
    method: 'POST',
    headers: {
      'xi-api-key':   ELEVEN_API_KEY,
      'Content-Type': 'application/json',
      'Accept':       'application/json',
      'Content-Length': Buffer.byteLength(payload)
    }
  }, (res) => {
    if (res.statusCode !== 200) {
      let err = '';
      res.on('data', c => err += c);
      res.on('end', () => reject(new Error('ElevenLabs ' + res.statusCode + ': ' + err.slice(0,300))));
      return;
    }
    res.on('data', c => chunks.push(c));
    res.on('end', () => resolve(JSON.parse(Buffer.concat(chunks).toString())));
  });
  req.on('error', reject);
  req.write(payload);
  req.end();
});

// ── Decode audio base64 → MP3 ─────────────────────────────────────────────────
const audioBuffer = Buffer.from(response.audio_base64, 'base64');
fs.writeFileSync(audioPath, audioBuffer);
console.log('ElevenLabs TTS done | ' + audioBuffer.length + ' bytes');

// ── Get exact audio duration via ffprobe ──────────────────────────────────────
const durOut = execSync(
  'docker exec qpc_ffmpeg_runner ffprobe -v quiet -show_entries format=duration -of csv=p=0 "' + contAudio + '"',
  { encoding: 'utf-8', timeout: 15000 }
).trim();
const audioDuration = parseFloat(durOut) || 28;

// ── Parse character timestamps → word timestamps ─────────────────────────────
const alignment = response.alignment || response.normalized_alignment || {};
const chars      = alignment.characters || [];
const startTimes = alignment.character_start_times_seconds || [];
const endTimes   = alignment.character_end_times_seconds   || [];

const wordTimings = [];

if (chars.length > 0) {
  // Build word timings from character alignment
  let wChars = [], wStart = null;
  for (let i = 0; i < chars.length; i++) {
    const c = chars[i];
    if (c === ' ' || c === '\n' || c === '\t') {
      if (wChars.length > 0) {
        wordTimings.push({
          word:  wChars.join('').replace(/[.,!?;:]+$/, ''),
          start: +wStart.toFixed(3),
          end:   +endTimes[i-1].toFixed(3)
        });
        wChars = []; wStart = null;
      }
    } else {
      if (wChars.length === 0) wStart = startTimes[i];
      wChars.push(c);
    }
  }
  // Last word
  if (wChars.length > 0) {
    wordTimings.push({
      word:  wChars.join('').replace(/[.,!?;:]+$/, ''),
      start: +wStart.toFixed(3),
      end:   +endTimes[endTimes.length-1].toFixed(3)
    });
  }
  console.log('Real word timings: ' + wordTimings.length + ' words from ElevenLabs character alignment');
} else {
  // Fallback: estimate from WPM if alignment missing
  console.warn('No alignment in response — using WPM estimate');
  const words = narration.trim().split(/\s+/);
  let cursor = 0.25;
  for (const w of words) {
    const dur = 0.38 * (0.8 + w.length * 0.04);
    wordTimings.push({ word: w.replace(/[.,!?;:]+$/, ''), start: +cursor.toFixed(3), end: +(cursor+dur).toFixed(3) });
    cursor += dur * 1.05;
  }
  // Scale to actual duration
  const rawEnd = wordTimings[wordTimings.length-1].end + 0.3;
  const scale  = (audioDuration - 0.3) / rawEnd;
  for (const wt of wordTimings) { wt.start = +(wt.start*scale).toFixed(3); wt.end = +(wt.end*scale).toFixed(3); }
}

console.log('Audio duration: ' + audioDuration.toFixed(2) + 's | Words: ' + wordTimings.length);
return [{ json: { ...jobData, audio_path: '/data/ffmpeg/input/' + jobId + '_voice.mp3', audio_duration: +audioDuration.toFixed(3), word_timings: wordTimings } }];

const fs      = require('fs');
const data    = $input.first().json;
const jobId   = data.job_id;
const timings = data.word_timings || [];
const hlWords = (data.highlight_keywords || []).map(w => w.toLowerCase().replace(/[^a-z]/g,''));
const n8nIn   = '/data/ffmpeg/input';

function toASS(sec) {
  if (!sec || isNaN(sec)) sec = 0;
  const h  = Math.floor(sec/3600);
  const m  = Math.floor((sec%3600)/60);
  const s  = Math.floor(sec%60);
  const cs = Math.round((sec%1)*100);
  return h+':'+String(m).padStart(2,'0')+':'+String(s).padStart(2,'0')+'.'+String(cs).padStart(2,'0');
}

// ── ASS Color helpers (ASS uses AABBGGRR hex format) ──────────────────────────
// Electric cobalt blue glow  #0044FF → BGR = FF4400
const GLOW_COLOR   = '&H00FF4400&';   // electric blue outline (glow)
const WHITE_ACTIVE = '&H00FFFFFF&';   // bright white — active word
const WHITE_DIM    = '&H99FFFFFF&';   // dimmed white — inactive words (99 = 60% alpha)
const SHADOW_COL   = '&HCC111111&';   // dark translucent shadow
// Keyword highlight: orange-yellow glow for power words
const KW_COLOR     = '&H0000CCFF&';   // orange glow (BGR: 00,CC,FF)
const KW_TEXT      = '&H00CCFFFF&';   // yellow text for keywords

// ── Build caption events: 3-word chunks, active word glows ───────────────────
const CHUNK = 3;
const lines = [];

for (let i = 0; i < timings.length; i += CHUNK) {
  const chunk = timings.slice(i, Math.min(i+CHUNK, timings.length));

  for (let j = 0; j < chunk.length; j++) {
    const wStart = chunk[j].start;
    const wEnd   = chunk[j].end;

    const parts = chunk.map((w, k) => {
      const word    = w.word;
      const isActive  = k === j;
      const isKw    = hlWords.some(h => word.toLowerCase().replace(/[^a-z]/g,'').includes(h));

      if (isKw && isActive) {
        // Active keyword: yellow text + orange glow + heavy blur
        return '{\c'+KW_TEXT+'\blur12\bord6\3c'+KW_COLOR+'\shad3\4c'+SHADOW_COL+'}' + word + '{\r}';
      } else if (isActive) {
        // Active word: bright white + electric blue glow bloom
        return '{\c'+WHITE_ACTIVE+'\blur10\bord5\3c'+GLOW_COLOR+'\shad3\4c'+SHADOW_COL+'}' + word + '{\r}';
      } else if (isKw) {
        // Inactive keyword: show in keyword color, dimmed glow
        return '{\c'+KW_TEXT+'\blur2\bord2\3c'+KW_COLOR+'\alpha&H66&}' + word + '{\r}';
      } else {
        // Inactive: dimmed, no glow
        return '{\c'+WHITE_DIM+'\blur0\bord0\shad0}' + word;
      }
    }).join(' ');

    // Slide-in animation: move from y+12 to final position over first 80ms
    const slideTag = (j === 0 && i === 0) ? '{\move(540,1430,540,1418,0,80)}' : '';
    lines.push('Dialogue: 0,'+toASS(wStart)+','+toASS(wEnd)+',Caption,,0,0,0,,'+slideTag+parts);
  }
}

// ── ASS file with Anton-style bold font definition ─────────────────────────────
// WrapStyle=2 = no wrapping (each line exactly as written)
// Alignment=2 = bottom center
// BorderStyle=1 = outline+shadow (NOT box)
// Outline=5 = thick outline (blurred = glow effect)
// Shadow=3 = drop shadow depth
const assContent = [
  '[Script Info]',
  'Title: Fitness Anatomy Captions',
  'ScriptType: v4.00+',
  'WrapStyle: 2',
  'PlayResX: 1080',
  'PlayResY: 1920',
  'ScaledBorderAndShadow: yes',
  '',
  '[V4+ Styles]',
  'Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding',
  // Anton-Regular, size 72, white text, electric blue outline, dark shadow, bold=-1, BorderStyle=1, Outline=5, Shadow=3, Align=2 (bottom center), MarginV=120
  'Style: Caption,Anton-Regular,72,&H00FFFFFF,&H000000FF,&H00FF4400,&HCC111111,-1,0,0,0,100,100,0,0,1,5,3,2,30,30,120,1',
  '',
  '[Events]',
  'Format: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text',
  ...lines
].join('\n');

const assPath = n8nIn + '/' + jobId + '_captions.ass';
fs.writeFileSync(assPath, assContent, 'utf8');
console.log('ASS captions: ' + lines.length + ' events | Anton-Regular 72px | glow: electric blue | keywords: ' + hlWords.join(','));

return [{ json: { ...data, ass_path: assPath } }];

const { execSync } = require('child_process');
const data   = $input.first().json;
const jobId  = data.job_id;
const N      = data.num_clips || 6;
const CLIP   = data.clip_dur_sec || 5;
const FADE   = 0.4;
const videoDur = (N * CLIP - Math.max(0, N-1) * FADE);

const bgmDir = '/ffmpeg/config/bgm';
const ls     = execSync('docker exec qpc_ffmpeg_runner bash -c "ls ' + bgmDir + '/*.mp3 2>/dev/null | sort"', { encoding: 'utf-8', timeout: 10000 }).trim();
if (!ls) throw new Error('No BGM tracks in /ffmpeg/config/bgm/ — add .mp3 files.');

const tracks = ls.split('\n').map(p => p.trim()).filter(Boolean);
const seed   = parseInt(String(jobId).replace(/\D/g,'').slice(-6)||'1', 10);
const picked = tracks[seed % tracks.length];

const bgmN8n  = '/data/ffmpeg/input/' + jobId + '_bgm.mp3';
const bgmCont = '/ffmpeg/input/'      + jobId + '_bgm.mp3';

const trim = 'docker exec qpc_ffmpeg_runner ffmpeg -y ' +
  '-stream_loop -1 -i "' + picked + '" ' +
  '-t ' + videoDur.toFixed(3) + ' ' +
  '-af "afade=t=in:st=0:d=1.5,afade=t=out:st=' + (videoDur-1.5).toFixed(3) + ':d=1.5,volume=0.22" ' +
  '-acodec libmp3lame -ab 128k "' + bgmCont + '" 2>&1 && echo TRIM_OK';

const res = execSync(trim, { encoding: 'utf-8', timeout: 30000 });
if (!res.includes('TRIM_OK')) throw new Error('BGM trim failed: ' + res.slice(-300));

console.log('BGM: ' + picked.split('/').pop() + ' | ' + videoDur.toFixed(1) + 's');

return [{ json: { ...data, bgm_path: bgmN8n } }];
